// Saved registers for kernel context switches.
struct context {
  uint64 ra;
  uint64 sp;

  // callee-saved
  uint64 s0;
  uint64 s1;
  uint64 s2;
  uint64 s3;
  uint64 s4;
  uint64 s5;
  uint64 s6;
  uint64 s7;
  uint64 s8;
  uint64 s9;
  uint64 s10;
  uint64 s11;

  // callee-saved FPU registers (fs0-fs11)
  uint64 fs0;
  uint64 fs1;
  uint64 fs2;
  uint64 fs3;
  uint64 fs4;
  uint64 fs5;
  uint64 fs6;
  uint64 fs7;
  uint64 fs8;
  uint64 fs9;
  uint64 fs10;
  uint64 fs11;
  uint64 fcsr;
};

// Per-CPU state.
struct cpu {
  struct proc *proc;          // The process running on this cpu, or null.
  struct context context;     // swtch() here to enter scheduler().
  int noff;                   // Depth of push_off() nesting.
  int intena;                 // Were interrupts enabled before push_off()?
};

extern struct cpu cpus[NCPU];

